#include <stdio.h>
int main() {
    int T, N, M;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        int grid[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                scanf("%d", &grid[i][j]);
            }
        }
        int max_sum = -1000000000;
        for (int i = 1; i < N - 1; i++) {
            for (int j = 1; j < M - 1; j++) {
                int sum = grid[i][j];
                if (i - 1 >= 0) sum += grid[i - 1][j];
                if (i + 1 < N) sum += grid[i + 1][j];
                if (j - 1 >= 0) sum += grid[i][j - 1];
                if (j + 1 < M) sum += grid[i][j + 1];
                max_sum = (max_sum > sum) ? max_sum : sum;
            }
        }
        printf("%d\n", max_sum);
    }
    return 0;
}

