const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readLine = () => input[idx++];
const readInt = () => parseInt(readLine());
const readInts = () => readLine().split(' ').map(x => parseInt(x));
const T = readInt();
for (let i = 0; i < T; i++) {
    const [N, M] = readInts();
    const grid = [];
    for (let j = 0; j < N; j++) {
        grid.push(readInts());
    }
    let max_sum = -1000000000;
    for (let j = 1; j < N - 1; j++) {
        for (let k = 1; k < M - 1; k++) {
            let sum = grid[j][k];
            if (j - 1 >= 0) sum += grid[j - 1][k];
            if (j + 1 < N) sum += grid[j + 1][k];
            if (k - 1 >= 0) sum += grid[j][k - 1];
            if (k + 1 < M) sum += grid[j][k + 1];
            max_sum = Math.max(max_sum, sum);
        }
    }
    console.log(max_sum);
}

